```rust
#[cfg(test)]
mod tag_filter_tests {
    use super::*;

    fn mock_tools() -> Vec<MockTool> {
        vec![
            MockTool::new("search").with_tags(&["api", "public", "read"]),
            MockTool::new("create").with_tags(&["api", "public", "write"]),
            MockTool::new("admin").with_tags(&["api", "private", "admin"]),
            MockTool::new("debug").with_tags(&["internal", "debug"]),
            MockTool::new("untagged"),
        ]
    }

    #[test]
    fn test_include_single_tag() {
        let tools = filter_tools(mock_tools(), Some(&["api"]), None);
        assert_eq!(tools.len(), 3); // search, create, admin
    }

    #[test]
    fn test_include_multiple_tags_and_logic() {
        let tools = filter_tools(mock_tools(), Some(&["api", "public"]), None);
        assert_eq!(tools.len(), 2); // search, create (both have api AND public)
    }

    #[test]
    fn test_exclude_single_tag() {
        let tools = filter_tools(mock_tools(), None, Some(&["private"]));
        assert_eq!(tools.len(), 4); // all except admin
    }

    #[test]
    fn test_exclude_multiple_tags_or_logic() {
        let tools = filter_tools(mock_tools(), None, Some(&["private", "internal"]));
        assert_eq!(tools.len(), 3); // search, create, untagged
    }

    #[test]
    fn test_include_and_exclude_combined() {
        let tools = filter_tools(
            mock_tools(),
            Some(&["api"]),
            Some(&["private"])
        );
        assert_eq!(tools.len(), 2); // search, create (api but not private)
    }

    #[test]
    fn test_case_insensitive() {
        let tools = filter_tools(mock_tools(), Some(&["API"]), None);
        assert_eq!(tools.len(), 3); // Should match "api" tags
    }

    #[test]
    fn test_empty_include_no_filter() {
        let tools = filter_tools(mock_tools(), Some(&[]), None);
        assert_eq!(tools.len(), 5); // All tools
    }

    #[test]
    fn test_no_matches() {
        let tools = filter_tools(mock_tools(), Some(&["nonexistent"]), None);
        assert!(tools.is_empty());
    }
}
