async fn test_list_tools_with_include_tags() {
    let server = ServerBuilder::new("test", "1.0")
        .tool(tagged_tool("search", &["api", "public"]))
        .tool(tagged_tool("admin", &["api", "private"]))
        .build();

    let request = ListToolsRequest {
        include_tags: Some(vec!["public".into()]),
        exclude_tags: None,
    };

    let result = server.list_tools_filtered(request).await.unwrap();
    assert_eq!(result.tools.len(), 1);
    assert_eq!(result.tools[0].name, "search");
